"""Evaluation CLI subcommands: kreview eval cpu|gpu|multimodal {run,prep,...}.

Registered in the main CLI via::

    from kreview.cli_eval import eval_app
    app.add_typer(eval_app, name="eval")

This keeps evaluation-specific code out of the 1,500-line cli.py.
"""

import os
import typer
import json
import time as _time
from pathlib import Path

import numpy as np
import pandas as pd
import structlog

log = structlog.get_logger()

eval_app = typer.Typer(name="eval", help="Model evaluation commands")

# Multimodal sub-command group: `kreview eval multimodal {run,prep,single,ablation,merge}`
multimodal_app = typer.Typer(
    name="multimodal",
    help="Cross-evaluator multimodal evaluation (stacking + ablation)",
)
eval_app.add_typer(multimodal_app, name="multimodal")

# Ablation sub-command group: `kreview eval ablate {cpu,gpu,merge}`
ablate_app = typer.Typer(
    name="ablate",
    help="Feature group ablation — finds optimal feature subset per evaluator",
)
eval_app.add_typer(ablate_app, name="ablate")


@ablate_app.command("cpu")
def eval_ablate_cpu(
    matrix: Path = typer.Option(..., help="Path to selected matrix parquet"),
    output: Path = typer.Option(".", help="Output directory for ablation JSON"),
    n_outer_folds: int = typer.Option(5, help="Outer CV folds (must match eval)"),
    n_inner_folds: int = typer.Option(3, help="Inner CV folds for subset selection"),
    seed: int = typer.Option(42, help="Random seed"),
):
    """CPU feature group ablation (LR, RF, XGB) with nested CV.

    Evaluates feature subsets across outer folds using inner CV
    to find the best feature group combination per model.
    Output: ``{evaluator}_ablation_cpu.json``
    """
    from kreview.eval_engine import ablate_feature_groups

    print("╔══ ABLATE CPU ═══════════════════════════════════════╗", flush=True)
    print(f"  Matrix:      {matrix}", flush=True)
    print(f"  Outer folds: {n_outer_folds}", flush=True)
    print(f"  Inner folds: {n_inner_folds}", flush=True)
    print(f"  Seed:        {seed}", flush=True)

    start = _time.time()
    result = ablate_feature_groups(
        matrix,
        models=("lr", "rf", "xgb"),
        n_outer_folds=n_outer_folds,
        n_inner_folds=n_inner_folds,
        random_state=seed,
        output_path=output,
    )

    elapsed = _time.time() - start
    if "error" in result:
        print(f"  ⚠ ERROR: {result['error']}", flush=True)
    elif result.get("passthrough"):
        print("  ℹ Passthrough (single feature group)", flush=True)
    else:
        print(
            f"  ✓ Ablation complete: {result.get('n_groups', 0)} groups, "
            f"{len(result.get('per_fold_results', []))} folds",
            flush=True,
        )
    print(f"  Time: {elapsed:.1f}s", flush=True)
    print("╚════════════════════════════════════════════════════╝", flush=True)


@ablate_app.command("gpu")
def eval_ablate_gpu(
    matrix: Path = typer.Option(..., help="Path to selected matrix parquet"),
    output: Path = typer.Option(".", help="Output directory for ablation JSON"),
    models: str = typer.Option("tabpfn,tabicl", help="Comma-separated GPU model names"),
    n_outer_folds: int = typer.Option(
        5, help="Outer CV folds (must match CPU ablation)"
    ),
    n_inner_folds: int = typer.Option(3, help="Inner CV folds for subset selection"),
    seed: int = typer.Option(42, help="Random seed"),
    device: str = typer.Option("cuda", help="PyTorch device"),
    max_gpu_features: int = typer.Option(150, help="Feature cap for GPU models"),
    eval_stats: Path = typer.Option(
        None,
        "--eval-stats",
        help="Path to eval_stats parquet for score-based feature capping",
    ),
):
    """GPU feature group ablation (TabPFN, TabICL) with nested CV.

    Uses ZERO-SHOT inference only in the inner CV loop (no fine-tuning).
    Output: ``{evaluator}_ablation_gpu.json``
    """
    model_tuple = tuple(m.strip() for m in models.split(","))
    _validate_gpu_models(model_tuple)
    from kreview.eval_engine import ablate_feature_groups

    print("╔══ ABLATE GPU ═══════════════════════════════════════╗", flush=True)
    print(f"  Matrix:      {matrix}", flush=True)
    print(f"  Models:      {model_tuple}", flush=True)
    print(f"  Device:      {device}", flush=True)

    start = _time.time()
    result = ablate_feature_groups(
        matrix,
        models=model_tuple,
        n_outer_folds=n_outer_folds,
        n_inner_folds=n_inner_folds,
        random_state=seed,
        output_path=output,
        device=device,
        max_gpu_features=max_gpu_features,
        eval_stats_path=eval_stats,
    )

    elapsed = _time.time() - start
    if "error" in result:
        print(f"  ⚠ ERROR: {result['error']}", flush=True)
    else:
        print("  ✓ GPU ablation complete", flush=True)
    print(f"  Time: {elapsed:.1f}s", flush=True)
    print("╚════════════════════════════════════════════════════╝", flush=True)


@ablate_app.command("merge")
def eval_ablate_merge(
    cpu_json: Path = typer.Option(..., help="Path to *_ablation_cpu.json"),
    gpu_json: Path = typer.Option(None, help="Path to *_ablation_gpu.json (optional)"),
    output: Path = typer.Option(".", help="Output directory for best_subset.json"),
):
    """Merge CPU + GPU ablation results into best_subset.json.

    Produces a unified per-model per-fold feature list consumed by
    ``kreview eval cpu --best-subset`` and ``kreview eval gpu --best-subset``.
    """
    from kreview.eval_engine import merge_ablation

    print("╔══ ABLATE MERGE ═════════════════════════════════════╗", flush=True)
    print(f"  CPU JSON: {cpu_json}", flush=True)
    print(f"  GPU JSON: {gpu_json or 'None'}", flush=True)

    result = merge_ablation(
        cpu_json_path=cpu_json,
        gpu_json_path=gpu_json,
        output_path=output,
    )

    n_models = len(result.get("per_model_per_fold_features", {}))
    print(f"  ✓ Merged: {n_models} models", flush=True)
    if result.get("gpu_error"):
        print("  ⚠ GPU ablation had errors — CPU-only results", flush=True)
    print("╚════════════════════════════════════════════════════╝", flush=True)


def _validate_gpu_models(models: tuple[str, ...], flag_name: str = "--models") -> None:
    """Pre-flight check: verify each requested GPU model can be imported and
    that TabPFN has a valid API token set via TABPFN_TOKEN env var.

    Validates the 4 supported GPU model names and exits with code 1 if any
    check fails, providing actionable error messages.
    """
    _VALID = {"tabpfn", "tabpfn_ft", "tabicl", "tabicl_ft"}
    _TABPFN_NAMES = {"tabpfn", "tabpfn_ft"}  # Both need tabpfn + token
    _TABICL_NAMES = {"tabicl", "tabicl_ft"}  # Both need tabicl

    for m in models:
        if m not in _VALID:
            print(
                f"ERROR: Unknown GPU model '{m}'. "
                f"Valid options: {', '.join(sorted(_VALID))}\n"
                f"  Tip: use 'tabpfn' (zero-shot) or 'tabpfn_ft' (fine-tuned)",
                flush=True,
            )
            raise typer.Exit(code=1)

        if m in _TABPFN_NAMES:
            try:
                import tabpfn  # noqa: F401
            except ImportError:
                print(
                    f"ERROR: GPU model '{m}' was requested but the tabpfn "
                    f"package is not installed.\n"
                    f"  Install with: pip install kreview[gpu]\n"
                    f"  Or remove '{m}' from {flag_name}.",
                    flush=True,
                )
                raise typer.Exit(code=1)
            if not os.environ.get("TABPFN_TOKEN"):
                print(
                    f"ERROR: GPU model '{m}' requires a TABPFN_TOKEN "
                    f"environment variable.\n"
                    f"  1. Register at https://ux.priorlabs.ai\n"
                    f"  2. Accept the license on the Licenses tab\n"
                    f"  3. export TABPFN_TOKEN='your-token-here'\n"
                    f"  Or remove '{m}' from {flag_name}.",
                    flush=True,
                )
                raise typer.Exit(code=1)
        elif m in _TABICL_NAMES:
            try:
                import tabicl  # noqa: F401
            except ImportError:
                print(
                    f"ERROR: GPU model '{m}' was requested but the tabicl "
                    f"package is not installed.\n"
                    f"  Install with: pip install kreview[gpu]",
                    flush=True,
                )
                raise typer.Exit(code=1)


# ── Shared helpers ────────────────────────────────────────────────────────────


def _load_matrix_and_labels(
    matrix_path: Path,
    label_col: str = "label",
    impute_strategy: str = "median",
) -> tuple[pd.DataFrame, np.ndarray, list[str], np.ndarray | None, np.ndarray | None]:
    """Load a feature matrix parquet and extract features, labels, metadata.

    Delegates label filtering and binary target construction to
    :func:`kreview.selection.build_binary_target` — the canonical source
    shared with ``kreview run`` and ``kreview select``.

    Uses the canonical ``LABEL_META_COLS`` set from ``kreview.core`` to
    exclude label/metadata columns.  This prevents data leakage — columns
    like ``max_vaf``, ``n_somatic_snvs`` must never be treated as features.

    Args:
        matrix_path: Path to a ``*_matrix.parquet`` file.
        label_col: Column containing label strings (default ``"label"``).
        impute_strategy: Imputation strategy for NaN values:
            ``"median"`` (default), ``"mean"``, or ``"zero"``.

    Returns:
        ``(model_df, y, feature_cols, cancer_types, assays)``

    Raises:
        typer.Exit: On validation errors (file not found, no features,
            insufficient data, or single-class target).
    """
    from kreview.core import LABEL_META_COLS
    from kreview.selection import build_binary_target, _impute

    if not matrix_path.exists():
        print(f"ERROR: Matrix not found: {matrix_path}", flush=True)
        raise typer.Exit(code=1)

    df = pd.read_parquet(matrix_path)
    print(f"  Loaded: {df.shape[0]} samples x {df.shape[1]} columns", flush=True)

    # ── Build binary target via shared library ──
    # build_binary_target raises ValueError for <20 samples or single-class.
    try:
        model_df, y = build_binary_target(df, label_col=label_col)
    except ValueError as exc:
        print(f"ERROR: {exc}", flush=True)
        log.error("load_matrix_target_failed", matrix=str(matrix_path), error=str(exc))
        raise typer.Exit(code=1)

    # ── Identify numeric feature columns ──
    # LABEL_META_COLS (22 entries) covers all label, metadata, and QC
    # columns that must not be used as model features.
    feature_cols = [
        c
        for c in model_df.select_dtypes(include=np.number).columns
        if c not in LABEL_META_COLS
    ]

    if not feature_cols:
        print("ERROR: No feature columns found in matrix", flush=True)
        log.error("no_feature_columns", matrix=str(matrix_path))
        raise typer.Exit(code=1)

    # ── Impute NaNs using shared strategy ──
    model_df[feature_cols] = _impute(model_df[feature_cols], impute_strategy)

    # ── Drop zero-variance features ──
    nonconst = [c for c in feature_cols if model_df[c].std() > 0]
    n_dropped = len(feature_cols) - len(nonconst)
    if n_dropped > 0:
        print(f"  Dropped {n_dropped} zero-variance features", flush=True)
        log.info("dropped_zero_variance", n_dropped=n_dropped, matrix=str(matrix_path))
    feature_cols = nonconst

    if not feature_cols:
        print("ERROR: All features have zero variance", flush=True)
        log.error("all_zero_variance", matrix=str(matrix_path))
        raise typer.Exit(code=1)

    # ── Extract metadata arrays ──
    cancer_types = model_df.get("CANCER_TYPE", None)
    if cancer_types is not None:
        cancer_types = cancer_types.values
    assays = model_df.get("access_version", None)
    if assays is not None:
        assays = assays.values

    return model_df, y, feature_cols, cancer_types, assays


def _save_results(
    results: dict,
    output_dir: Path,
    filename: str,
    extra_meta: dict | None = None,
) -> Path:
    """Save model results to JSON with optional metadata."""
    output_dir.mkdir(parents=True, exist_ok=True)
    out_path = output_dir / filename

    if extra_meta and "error" not in results:
        results.update(extra_meta)

    with open(out_path, "w") as f:
        json.dump(results, f, indent=2, default=str)

    print(f"  Output: {out_path}", flush=True)
    return out_path


def _save_fitted_models(
    fitted_models: dict[str, object],
    output_dir: Path,
    evaluator: str,
    skip_gpu_joblib: bool = False,
) -> None:
    """Persist fitted model objects to joblib for downstream SHAP rendering.

    Writes ``{evaluator}_{model_name}_model.joblib`` for each fitted model,
    matching the naming convention expected by the report template's SHAP
    beeswarm section.

    Args:
        fitted_models: Dict mapping model name → fitted model object.
            Example: ``{"lr": pipeline, "rf": rf_model, "tabpfn": tabpfn_model}``.
        output_dir: Directory to write joblib files.
        evaluator: Evaluator name (e.g., ``"FSCOnTarget"``).
        skip_gpu_joblib: If True, skip GPU models (TabPFN/TabICL can be >200MB).
    """
    import joblib

    GPU_MODELS = {"tabpfn", "tabpfn_ft", "tabicl", "tabicl_ft"}

    for name, model in fitted_models.items():
        if model is None:
            continue
        if skip_gpu_joblib and name in GPU_MODELS:
            log.info(
                "joblib_skip_gpu",
                model=name,
                evaluator=evaluator,
                reason="--skip-gpu-joblib",
            )
            continue
        out_path = output_dir / f"{evaluator}_{name}_model.joblib"
        try:
            joblib.dump(model, out_path)

            # Post-write validation: catch truncated/corrupt files.
            # A valid fitted sklearn model is always >100 bytes.
            # A truncated pickle header from failed serialization is exactly
            # 2 bytes (\x80\x04). Use 100 bytes as a generous safety margin.
            file_size = out_path.stat().st_size
            if file_size < 100:
                out_path.unlink()  # Remove corrupt file
                log.error(
                    "joblib_corrupt_removed",
                    model=name,
                    evaluator=evaluator,
                    size_bytes=file_size,
                    reason="File too small — likely failed to serialize "
                    "(e.g. unpicklable lambda in model object)",
                )
            else:
                log.info(
                    "joblib_saved",
                    model=name,
                    evaluator=evaluator,
                    path=str(out_path),
                    size_mb=round(file_size / 1024 / 1024, 1),
                )
        except Exception as e:
            # Clean up any partial file left by failed dump
            if out_path.exists():
                out_path.unlink()
            log.error(
                "joblib_save_failed",
                model=name,
                evaluator=evaluator,
                error=str(e),
            )


# ── eval cpu ──────────────────────────────────────────────────────────────────


@eval_app.command("cpu")
def eval_cpu(
    matrices_dir: Path = typer.Option(
        ...,
        "--matrices-dir",
        help="Directory containing *_matrix.parquet files from kreview extract",
    ),
    output: Path = typer.Option("output/", help="Output directory"),
    models: str = typer.Option(
        "lr,rf,xgb",
        "--models",
        help="Comma-separated CPU models: lr,rf,xgb",
    ),
    cv_folds: int = typer.Option(5, "--cv-folds", help="Cross-validation folds"),
    resume: bool = typer.Option(
        False, "--resume", help="Skip evaluators with existing results"
    ),
    seed: int = typer.Option(
        42,
        "--seed",
        help="Random seed for reproducibility.",
    ),
    deterministic: bool = typer.Option(
        True,
        "--deterministic/--no-deterministic",
        help="Enable PyTorch deterministic mode (slower but reproducible).",
    ),
    best_subset: Path = typer.Option(
        None,
        "--best-subset",
        help="Path to *_best_subset.json from ablation merge (enables nested CV)",
    ),
):
    """Per-evaluator evaluation using LR, RF, XGBoost (CPU).

    Iterates over all *_matrix.parquet files in --matrices-dir,
    trains the specified models, and writes *_model_results.json
    to --output.
    """
    from kreview.eval_engine import cpu_models
    from kreview.reproducibility import seed_everything

    seed_everything(seed, deterministic=deterministic)

    print("=== kreview eval cpu ===", flush=True)
    print(f"  --matrices-dir : {matrices_dir}", flush=True)
    print(f"  --output       : {output}", flush=True)
    print(f"  --models       : {models}", flush=True)
    print(f"  --cv-folds     : {cv_folds}", flush=True)
    print(f"  --resume       : {resume}", flush=True)
    print("", flush=True)

    if not matrices_dir.exists():
        print(f"ERROR: Matrices directory not found: {matrices_dir}", flush=True)
        raise typer.Exit(code=1)

    matrix_files = sorted(matrices_dir.glob("*_matrix.parquet"))
    if not matrix_files:
        print(f"ERROR: No *_matrix.parquet files in {matrices_dir}", flush=True)
        raise typer.Exit(code=1)

    print(f"  Found {len(matrix_files)} evaluator matrices", flush=True)

    models_list = [m.strip() for m in models.split(",")]
    output.mkdir(parents=True, exist_ok=True)

    for mf in matrix_files:
        evaluator = mf.stem.replace("_matrix", "")
        out_file = output / f"{evaluator}_model_results.json"

        # Resume: check for existing model keys
        if resume and out_file.exists():
            with open(out_file) as f:
                existing = json.load(f)
            existing_models = {
                k.replace("auc_", "")
                for k in existing
                if k.startswith("auc_") and isinstance(existing[k], (int, float))
            }
            remaining = set(models_list) - existing_models
            if not remaining:
                print(
                    f"  SKIP ({evaluator}): all {len(existing_models)} models computed",
                    flush=True,
                )
                continue
            print(
                f"  RESUME ({evaluator}): running {remaining} "
                f"(existing: {existing_models})",
                flush=True,
            )

        print(f"\n  Evaluating: {evaluator}", flush=True)
        t0 = _time.time()

        try:
            model_df, y, feature_cols, c_types, a_types = _load_matrix_and_labels(mf)

            # ── Train/test split (v0.0.16+: persisted in labels.parquet) ──
            has_split = "split" in model_df.columns
            if has_split:
                train_mask = model_df["split"] == "train"
                test_mask = model_df["split"] == "test"
                n_train = int(train_mask.sum())
                n_test = int(test_mask.sum())
                print(
                    f"  Holdout split: {n_train} train / {n_test} test",
                    flush=True,
                )

                if n_train < 20 or n_test < 5:
                    log.warning(
                        "holdout_split_too_small",
                        evaluator=evaluator,
                        n_train=n_train,
                        n_test=n_test,
                        action="falling back to full CV",
                    )
                    has_split = False

            if has_split:
                X_train = model_df.loc[train_mask, feature_cols].values
                y_train = y[train_mask.values]  # type: ignore[index]
                X_test = model_df.loc[test_mask, feature_cols].values
                y_test = y[test_mask.values]  # type: ignore[index]
                train_labels = (
                    model_df.loc[train_mask, "label"].values
                    if "label" in model_df.columns
                    else None
                )
                test_labels = (
                    model_df.loc[test_mask, "label"].values
                    if "label" in model_df.columns
                    else None
                )
            else:
                X_train = model_df[feature_cols].values
                y_train = y
                X_test = None
                y_test = None
                train_labels = (
                    model_df["label"].values if "label" in model_df.columns else None
                )
                test_labels = None

            # ── Load ablation results if provided ──
            per_fold_data = None
            fold_assign = None
            if best_subset is not None:
                bs_path = best_subset
                if bs_path.is_dir():
                    bs_path = bs_path / f"{evaluator}_best_subset.json"
                if bs_path.exists():
                    with open(bs_path) as f:
                        bs_data = json.load(f)
                    if not bs_data.get("passthrough", False):
                        per_fold_data = bs_data.get("per_model_per_fold_features")
                        fold_assign = bs_data.get("fold_assignment")
                        print(f"  Using best_subset: {bs_path.name}", flush=True)
                    else:
                        print(
                            "  Passthrough (single group) — using all features",
                            flush=True,
                        )
                else:
                    print(f"  ⚠ best_subset not found: {bs_path}", flush=True)

            results, lr, rf, xgb = cpu_models(
                X_train,
                y_train,
                feature_names=feature_cols,
                cancer_types=(
                    c_types[train_mask.values]  # type: ignore[index]
                    if has_split and c_types is not None
                    else c_types
                ),
                assays=(
                    a_types[train_mask.values]  # type: ignore[index]
                    if has_split and a_types is not None
                    else a_types
                ),
                n_folds=cv_folds,
                random_state=seed,
                sample_labels=train_labels,
                per_fold_features=per_fold_data,
                fold_assignment=fold_assign,
            )

            # ── Holdout evaluation (v0.0.16+) ──
            if has_split and X_test is not None and len(y_test) > 0:
                from kreview.eval_engine import evaluate_holdout

                for model_name, fitted_model in [("lr", lr), ("rf", rf), ("xgb", xgb)]:
                    if fitted_model is not None:
                        # When nested CV is active, the refitted model uses a
                        # feature subset. Slice X_test to match (GAP 1 fix).
                        refit_feats = results.get(f"{model_name}_refit_features")
                        if refit_feats and per_fold_data is not None:
                            refit_idx = [
                                feature_cols.index(f)
                                for f in refit_feats
                                if f in feature_cols
                            ]
                            X_test_model = X_test[:, refit_idx] if refit_idx else X_test
                        else:
                            X_test_model = X_test

                        holdout_res = evaluate_holdout(
                            fitted_model,
                            X_test_model,
                            y_test,
                            model_name,
                            sample_labels=test_labels,
                        )
                        results.update(holdout_res)

                results["holdout_n_train"] = int(train_mask.sum())
                results["holdout_n_test"] = int(test_mask.sum())

            # Add sample IDs for multimodal alignment.
            # CRITICAL: must use train-split only — oof_probs from
            # cross_val_predict covers train rows only, not the full DF.
            train_id_df = model_df.loc[train_mask] if has_split else model_df
            id_col = "sample_id" if "sample_id" in train_id_df.columns else "SAMPLE_ID"
            if id_col in train_id_df.columns:
                results["oof_sample_ids"] = train_id_df[id_col].tolist()
                log.info(
                    "oof_sample_ids_set",
                    evaluator=evaluator,
                    n_ids=len(results["oof_sample_ids"]),
                    source="train_split" if has_split else "full_df",
                )

            _save_results(
                results,
                output,
                f"{evaluator}_model_results.json",
                extra_meta={"evaluator": evaluator, "matrix_path": str(mf)},
            )

            # Persist fitted models for downstream SHAP rendering
            cpu_fitted = {}
            if lr is not None:
                cpu_fitted["lr"] = lr
            if rf is not None:
                cpu_fitted["rf"] = rf
            if xgb is not None:
                cpu_fitted["xgb"] = xgb
            _save_fitted_models(cpu_fitted, output, evaluator)

            def _fmt(v):
                return "N/A" if v is None else f"{v:.3f}"

            elapsed = _time.time() - t0
            holdout_info = ""
            if has_split:
                holdout_auc = results.get("holdout_rf_auc")
                holdout_info = f" | Holdout_RF={_fmt(holdout_auc)}"
            print(
                f"  {evaluator}: AUC_LR={_fmt(results.get('auc_lr'))}, "
                f"AUC_RF={_fmt(results.get('auc_rf'))}, "
                f"AUC_XGB={_fmt(results.get('auc_xgb'))}"
                f"{holdout_info} "
                f"in {elapsed:.1f}s",
                flush=True,
            )
        except SystemExit:
            raise  # re-raise typer.Exit
        except Exception as e:
            log.error("eval_cpu_evaluator_failed", evaluator=evaluator, error=str(e))
            print(f"  ERROR ({evaluator}): {e}", flush=True)
            continue

    print("\n=== eval cpu complete ===", flush=True)


# ── eval gpu ──────────────────────────────────────────────────────────────────


@eval_app.command("gpu")
def eval_gpu(
    matrices_dir: Path = typer.Option(
        ...,
        "--matrices-dir",
        help="Directory containing *_matrix.parquet files from kreview extract",
    ),
    output: Path = typer.Option("output/", help="Output directory"),
    models: str = typer.Option(
        "tabpfn,tabicl",
        "--models",
        help="Comma-separated GPU models: tabpfn,tabpfn_ft,tabicl,tabicl_ft",
    ),
    cv_folds: int = typer.Option(5, "--cv-folds", help="Cross-validation folds"),
    finetune_epochs: int = typer.Option(
        50, "--finetune-epochs", help="Fine-tuning epochs for _ft variants"
    ),
    finetune_lr: float = typer.Option(
        1e-5, "--finetune-lr", help="Fine-tuning learning rate for _ft variants"
    ),
    device: str = typer.Option("cuda", "--device", help="PyTorch device: cuda, cpu"),
    compute_shap: bool = typer.Option(False, "--shap", help="Compute SHAP values"),
    shap_samples: int = typer.Option(500, "--shap-samples", help="Max SHAP samples"),
    resume: bool = typer.Option(
        False, "--resume", help="Skip evaluators with existing results"
    ),
    skip_gpu_joblib: bool = typer.Option(
        False,
        "--skip-gpu-joblib",
        help="Skip saving GPU model joblib files (can be >200MB each)",
    ),
    seed: int = typer.Option(
        42,
        "--seed",
        help="Random seed for reproducibility.",
    ),
    deterministic: bool = typer.Option(
        True,
        "--deterministic/--no-deterministic",
        help="Enable PyTorch deterministic mode (slower but reproducible).",
    ),
    max_gpu_features: int = typer.Option(
        150,
        "--max-gpu-features",
        help=(
            "Maximum features for GPU models. If feature count exceeds this, "
            "the top N are selected by mutual information from eval_stats. "
            "Set to 0 to disable capping."
        ),
    ),
    best_subset: Path = typer.Option(
        None,
        "--best-subset",
        help="Path to *_best_subset.json from ablation merge (enables nested CV)",
    ),
):
    """Per-evaluator evaluation using TabPFN, TabICL (GPU).

    Each model name encodes its variant: 'tabpfn' = zero-shot,
    'tabpfn_ft' = fine-tuned, 'tabicl' = zero-shot, 'tabicl_ft' = fine-tuned.
    Iterates over all *_matrix.parquet files and writes results JSONs.
    """
    from kreview.eval_engine import gpu_models
    from kreview.reproducibility import seed_everything

    seed_everything(seed, deterministic=deterministic)

    print("=== kreview eval gpu ===", flush=True)
    print(f"  --matrices-dir   : {matrices_dir}", flush=True)
    print(f"  --output         : {output}", flush=True)
    print(f"  --models         : {models}", flush=True)
    print(f"  --device         : {device}", flush=True)
    print(f"  --finetune-epochs: {finetune_epochs}", flush=True)
    print(f"  --cv-folds       : {cv_folds}", flush=True)
    print(f"  --resume         : {resume}", flush=True)
    print("", flush=True)

    if not matrices_dir.exists():
        print(f"ERROR: Matrices directory not found: {matrices_dir}", flush=True)
        raise typer.Exit(code=1)

    matrix_files = sorted(matrices_dir.glob("*_matrix.parquet"))
    if not matrix_files:
        print(f"ERROR: No *_matrix.parquet files in {matrices_dir}", flush=True)
        raise typer.Exit(code=1)

    print(f"  Found {len(matrix_files)} evaluator matrices", flush=True)

    models_list = tuple(m.strip() for m in models.split(","))

    _validate_gpu_models(models_list, flag_name="--models")

    output.mkdir(parents=True, exist_ok=True)

    for mf in matrix_files:
        evaluator = mf.stem.replace("_matrix", "")
        out_file = output / f"{evaluator}_model_results.json"

        # Resume: check existing model keys
        existing_results = {}
        if resume and out_file.exists():
            with open(out_file) as f:
                existing_results = json.load(f)
            existing_models = {
                k.replace("auc_", "")
                for k in existing_results
                if k.startswith("auc_")
                and isinstance(existing_results[k], (int, float))
            }
            remaining = set(models_list) - existing_models
            if not remaining:
                print(f"  SKIP ({evaluator}): all models computed", flush=True)
                continue
            models_list_run = tuple(remaining)
            print(f"  RESUME ({evaluator}): running {remaining}", flush=True)
        else:
            models_list_run = models_list

        print(f"\n  Evaluating: {evaluator} with {models_list_run}", flush=True)
        t0 = _time.time()

        try:
            model_df, y, feature_cols, c_types, a_types = _load_matrix_and_labels(mf)

            # ── Train/test split (v0.0.16+) ──
            has_split = "split" in model_df.columns
            if has_split:
                train_mask = model_df["split"] == "train"
                test_mask = model_df["split"] == "test"
                n_train = int(train_mask.sum())
                n_test = int(test_mask.sum())
                print(f"  Holdout split: {n_train} train / {n_test} test", flush=True)
                if n_train < 20 or n_test < 5:
                    log.warning(
                        "holdout_split_too_small",
                        evaluator=evaluator,
                        n_train=n_train,
                        n_test=n_test,
                        action="falling back to full CV",
                    )
                    has_split = False

            if has_split:
                X_train = model_df.loc[train_mask, feature_cols].values
                y_train = y[train_mask.values]  # type: ignore[index]
                X_test = model_df.loc[test_mask, feature_cols].values
                y_test = y[test_mask.values]  # type: ignore[index]
                train_labels = (
                    model_df.loc[train_mask, "label"].values
                    if "label" in model_df.columns
                    else None
                )
                test_labels = (
                    model_df.loc[test_mask, "label"].values
                    if "label" in model_df.columns
                    else None
                )
            else:
                X_train = model_df[feature_cols].values
                y_train = y
                X_test = None
                y_test = None
                train_labels = (
                    model_df["label"].values if "label" in model_df.columns else None
                )
                test_labels = None

            # ── Load eval_stats for intelligent GPU feature capping ──
            gpu_cap = max_gpu_features if max_gpu_features > 0 else None
            _eval_stats = None
            if gpu_cap is not None:
                stats_file = matrices_dir / f"{evaluator}_eval_stats.parquet"
                if stats_file.exists():
                    try:
                        _eval_stats = pd.read_parquet(stats_file)
                        log.info(
                            "eval_stats_loaded_for_gpu_cap",
                            evaluator=evaluator,
                            n_features=len(_eval_stats),
                        )
                    except Exception as exc:
                        log.warning(
                            "eval_stats_load_failed",
                            evaluator=evaluator,
                            error=str(exc),
                        )

            # ── Load ablation results if provided ──
            per_fold_data = None
            fold_assign = None
            if best_subset is not None:
                bs_path = best_subset
                if bs_path.is_dir():
                    bs_path = bs_path / f"{evaluator}_best_subset.json"
                if bs_path.exists():
                    with open(bs_path) as f:
                        bs_data = json.load(f)
                    if not bs_data.get("passthrough", False):
                        per_fold_data = bs_data.get("per_model_per_fold_features")
                        fold_assign = bs_data.get("fold_assignment")
                        print(f"  Using best_subset: {bs_path.name}", flush=True)
                else:
                    print(f"  ⚠ best_subset not found: {bs_path}", flush=True)

            results, fitted = gpu_models(
                X_train,
                y_train,
                feature_names=feature_cols,
                cancer_types=(
                    c_types[train_mask.values]  # type: ignore[index]
                    if has_split and c_types is not None
                    else c_types
                ),
                assays=(
                    a_types[train_mask.values]  # type: ignore[index]
                    if has_split and a_types is not None
                    else a_types
                ),
                n_folds=cv_folds,
                random_state=seed,
                models=models_list_run,
                device=device,
                finetune_epochs=finetune_epochs,
                finetune_lr=finetune_lr,
                compute_shap=compute_shap,
                shap_samples=shap_samples,
                sample_labels=train_labels,
                max_gpu_features=gpu_cap,
                eval_stats=_eval_stats,
                per_fold_features=per_fold_data,
                fold_assignment=fold_assign,
            )

            # ── Holdout evaluation (v0.0.16+) ──
            if has_split and X_test is not None and len(y_test) > 0:
                from kreview.eval_engine import evaluate_holdout

                # Apply same GPU feature cap to X_test (dimension must match)
                cap_idx = results.get("gpu_feature_cap_indices")
                X_test_gpu = X_test[:, cap_idx] if cap_idx is not None else X_test

                for model_name, fitted_model in fitted.items():
                    if fitted_model is not None:
                        # When nested CV is active, the fitted GPU model uses
                        # a feature subset. Slice X_test to match (GAP 1 fix).
                        refit_feats = results.get(f"{model_name}_refit_features")
                        if refit_feats and per_fold_data is not None:
                            refit_idx = [
                                feature_cols.index(f)
                                for f in refit_feats
                                if f in feature_cols
                            ]
                            X_test_model = (
                                X_test[:, refit_idx] if refit_idx else X_test_gpu
                            )
                        else:
                            X_test_model = X_test_gpu

                        holdout_res = evaluate_holdout(
                            fitted_model,
                            X_test_model,
                            y_test,
                            model_name,
                            sample_labels=test_labels,
                        )
                        results.update(holdout_res)

                results["holdout_n_train"] = n_train
                results["holdout_n_test"] = n_test

            # Add sample IDs for multimodal alignment.
            # CRITICAL: must use train-split only — oof_probs from
            # cross_val_predict covers train rows only, not the full DF.
            train_id_df = model_df.loc[train_mask] if has_split else model_df
            id_col = "sample_id" if "sample_id" in train_id_df.columns else "SAMPLE_ID"
            if id_col in train_id_df.columns:
                results["oof_sample_ids"] = train_id_df[id_col].tolist()
                log.info(
                    "oof_sample_ids_set",
                    evaluator=evaluator,
                    n_ids=len(results["oof_sample_ids"]),
                    source="train_split" if has_split else "full_df",
                )

            # Merge with existing results if resuming
            if existing_results:
                existing_results.update(results)
                results = existing_results

            _save_results(
                results,
                output,
                f"{evaluator}_model_results.json",
                extra_meta={"evaluator": evaluator, "matrix_path": str(mf)},
            )

            # Persist fitted GPU models for downstream SHAP rendering
            _save_fitted_models(
                fitted, output, evaluator, skip_gpu_joblib=skip_gpu_joblib
            )

            elapsed = _time.time() - t0
            any_auc = False
            for mn in models_list_run:
                auc_val = results.get(f"auc_{mn}")
                holdout_val = results.get(f"holdout_{mn}_auc")
                if auc_val is not None:
                    any_auc = True
                    holdout_str = f" | Holdout={holdout_val:.3f}" if holdout_val else ""
                    print(
                        f"  {evaluator}/{mn}: AUC={auc_val:.3f}{holdout_str}",
                        flush=True,
                    )

            # Visible warning when all GPU models failed silently
            if not any_auc:
                print(
                    f"  ⚠ WARNING: No GPU models produced AUC for {evaluator}",
                    flush=True,
                )
                for k, v in results.items():
                    if k.endswith("_error"):
                        print(f"    {k}: {v}", flush=True)

            print(f"  Completed in {elapsed:.1f}s", flush=True)

        except SystemExit:
            raise
        except Exception as e:
            log.error("eval_gpu_evaluator_failed", evaluator=evaluator, error=str(e))
            print(f"  ERROR ({evaluator}): {e}", flush=True)
            continue

    print("\n=== eval gpu complete ===", flush=True)

    # ── Fail loudly if NO models produced valid results ──
    any_results = False
    for mf in matrix_files:
        evaluator = mf.stem.replace("_matrix", "")
        out_file = output / f"{evaluator}_model_results.json"
        if out_file.exists():
            with open(out_file) as f:
                d = json.load(f)
            if any(k.startswith("auc_") and isinstance(d[k], (int, float)) for k in d):
                any_results = True
                break

    if not any_results:
        print(
            "ERROR: No GPU models produced valid results. "
            "Check that tabpfn/tabicl are installed in the container.",
            flush=True,
        )
        log.error(
            "gpu_eval_all_models_failed",
            n_matrices=len(matrix_files),
            models=models,
        )
        raise typer.Exit(code=1)


# ── eval multimodal ───────────────────────────────────────────────────────────


@multimodal_app.command("run")
def eval_multimodal(
    results_dir: Path = typer.Option(
        ...,
        "--results-dir",
        help="Directory with *_model_results.json files from eval cpu/gpu",
    ),
    super_matrix: Path = typer.Option(
        None,
        "--super-matrix",
        help="Optional path to super_matrix.parquet for raw-feature strategy",
    ),
    output: Path = typer.Option("output/", help="Output directory"),
    models: str = typer.Option(
        "rf,xgb",
        "--models",
        help="Comma-separated CPU models for multimodal evaluation (lr,rf,xgb)",
    ),
    gpu_models: str = typer.Option(
        "",
        "--gpu-models",
        help="Comma-separated GPU models: tabpfn_ft,tabicl_ft. Empty = CPU only.",
    ),
    top_percentile: float = typer.Option(
        10.0,
        "--top-percentile",
        help="Top N%% features for MI selection (matches per-evaluator pipeline)",
    ),
    multimodal_selection: str = typer.Option(
        "mi",
        "--multimodal-selection",
        help="Multimodal feature selection: mi (default, fast) or boruta_shap (interaction-aware)",
    ),
    cv_folds: int = typer.Option(5, "--cv-folds", help="Cross-validation folds"),
    device: str = typer.Option("cuda", "--device", help="PyTorch device: cuda, cpu"),
    finetune_epochs: int = typer.Option(
        50, "--finetune-epochs", help="GPU fine-tuning epochs for _ft variants"
    ),
    finetune_lr: float = typer.Option(
        1e-5, "--finetune-lr", help="GPU fine-tuning learning rate"
    ),
    seed: int = typer.Option(
        42,
        "--seed",
        help="Random seed for reproducibility.",
    ),
    deterministic: bool = typer.Option(
        True,
        "--deterministic/--no-deterministic",
        help="Enable PyTorch deterministic mode (slower but reproducible).",
    ),
):
    """Cross-evaluator multimodal evaluation with stacking and ablation.

    Reads per-evaluator model_results.json files for OOF probabilities
    and combines them into a stacking matrix.  Three strategies are run:

    1. **Stacking**: Meta-learner on OOF probabilities across evaluators
    2. **Raw features** (if --super-matrix provided): MI or Boruta-SHAP selected features
    3. **Ablation**: Leave-one-evaluator-out importance analysis
    """
    from kreview.eval_engine import multimodal_eval as _multimodal_eval
    from kreview.reproducibility import seed_everything

    seed_everything(seed, deterministic=deterministic)

    print("=== kreview eval multimodal run ===", flush=True)
    print(f"  --results-dir        : {results_dir}", flush=True)
    print(f"  --super-matrix       : {super_matrix or '(not provided)'}", flush=True)
    print(f"  --output             : {output}", flush=True)
    print(f"  --models             : {models}", flush=True)
    print(f"  --gpu-models         : {gpu_models or '(none)'}", flush=True)
    print(f"  --top-percentile     : {top_percentile}", flush=True)
    print(f"  --multimodal-selection: {multimodal_selection}", flush=True)
    print(f"  --cv-folds           : {cv_folds}", flush=True)
    print(f"  --device             : {device}", flush=True)
    print(f"  --finetune-epochs    : {finetune_epochs}", flush=True)
    print("", flush=True)

    gpu_model_list = tuple(m.strip() for m in gpu_models.split(",") if m.strip())

    _validate_gpu_models(gpu_model_list, flag_name="--gpu-models")

    log.info(
        "eval_multimodal_start",
        results_dir=str(results_dir),
        super_matrix=str(super_matrix) if super_matrix else None,
        models=models,
        gpu_models=gpu_models,
        top_percentile=top_percentile,
        multimodal_selection=multimodal_selection,
        cv_folds=cv_folds,
    )

    # ── Validation ──
    if not results_dir.exists():
        print(f"ERROR: Results directory not found: {results_dir}", flush=True)
        raise typer.Exit(code=1)

    json_files = sorted(results_dir.glob("*_model_results.json"))
    cpu_count = sum(1 for f in json_files if "_gpu_model_results.json" not in f.name)
    gpu_count = len(json_files) - cpu_count
    if not json_files:
        print(f"ERROR: No *_model_results.json files in {results_dir}", flush=True)
        raise typer.Exit(code=1)
    print(
        f"  Found {cpu_count} CPU + {gpu_count} GPU evaluator result files", flush=True
    )

    if super_matrix is not None and not super_matrix.exists():
        print(f"ERROR: Super-matrix not found: {super_matrix}", flush=True)
        raise typer.Exit(code=1)

    models_list = tuple(m.strip() for m in models.split(",") if m.strip())
    if not models_list:
        print("ERROR: No models specified", flush=True)
        raise typer.Exit(code=1)

    # ── Run multimodal evaluation ──
    t0 = _time.time()
    try:
        results = _multimodal_eval(
            results_dir=results_dir,
            super_matrix_path=super_matrix,
            models=models_list,
            gpu_models=gpu_model_list,
            device=device,
            finetune_epochs=finetune_epochs,
            finetune_lr=finetune_lr,
            n_folds=cv_folds,
            top_percentile=top_percentile,
            random_state=seed,
            multimodal_selection=multimodal_selection,
        )
    except (FileNotFoundError, ValueError) as e:
        print(f"ERROR: {e}", flush=True)
        log.error("multimodal_eval_failed", error=str(e))
        raise typer.Exit(code=1)
    except Exception as e:
        log.error("multimodal_eval_unexpected_error", error=str(e))
        print(f"ERROR: Unexpected error: {e}", flush=True)
        raise typer.Exit(code=1)

    elapsed = _time.time() - t0

    # ── Display summary ──
    print(f"\n  Evaluators: {results.get('n_evaluators', 0)}", flush=True)
    print(
        f"  Best single-evaluator: {results.get('best_single_evaluator')} "
        f"(AUC={results.get('best_single_auc', 'N/A')})",
        flush=True,
    )

    # Stacking results
    stacking = results.get("stacking", {})
    if stacking:
        print("\n  Stacking results:", flush=True)
        for k, v in sorted(stacking.items()):
            if k.startswith("auc_stacking_") and not k.endswith(
                ("_ci_lower", "_ci_upper")
            ):
                mn = k.replace("auc_stacking_", "")
                delta_key = f"stacking_{mn}_vs_best_single"
                delta = stacking.get(delta_key)
                delta_str = f" (Δ={delta:+.3f})" if delta is not None else ""
                print(f"    {mn}: AUC={v:.3f}{delta_str}", flush=True)
    elif "stacking_error" in results:
        print(f"\n  Stacking ERROR: {results['stacking_error']}", flush=True)

    # Raw features results
    raw_results = results.get("raw_features", {})
    if raw_results:
        print(
            f"\n  Raw features ({results.get('raw_n_features_selected', '?')} selected):",
            flush=True,
        )
        for k, v in sorted(raw_results.items()):
            if k.startswith("auc_raw_") and not k.endswith(("_ci_lower", "_ci_upper")):
                print(f"    {k.replace('auc_raw_', '')}: AUC={v:.3f}", flush=True)

    # Ablation results
    ablation = results.get("ablation", {})
    if ablation:
        print(f"\n  Ablation (model={results.get('ablation_model')}):", flush=True)
        for eval_name, info in list(ablation.items())[:10]:
            if "error" in info:
                print(f"    {eval_name}: ERROR", flush=True)
            else:
                print(
                    f"    {eval_name}: Δ={info.get('delta', 0):.3f} "
                    f"(AUC-without={info.get('auc_without', 'N/A')})",
                    flush=True,
                )

    # ── Save results ──
    _save_results(
        results,
        output,
        "multimodal_results.json",
        extra_meta={"results_dir": str(results_dir), "elapsed_sec": elapsed},
    )

    print(f"\n=== eval multimodal run complete ({elapsed:.1f}s) ===", flush=True)


# ── eval multimodal prep ──────────────────────────────────────────────────────


@multimodal_app.command("prep")
def eval_multimodal_prep(
    results_dir: Path = typer.Option(
        ...,
        "--results-dir",
        help="Directory with *_model_results.json files from eval cpu/gpu",
    ),
    super_matrix: Path = typer.Option(
        None,
        "--super-matrix",
        help="Optional path to super_matrix.parquet for raw-feature strategy",
    ),
    multimodal_selection: str = typer.Option(
        "mi",
        "--multimodal-selection",
        help="Feature selection for raw features: mi (default) or boruta_shap",
    ),
    top_percentile: float = typer.Option(
        10.0,
        "--top-percentile",
        help="Top N%% features for MI selection",
    ),
    seed: int = typer.Option(42, "--seed", help="Random seed"),
    output: Path = typer.Option("output/", help="Output directory"),
):
    """Stage 1: Build stacking + raw-feature matrices from evaluator results.

    Produces ``stacking_matrix.parquet``, optionally
    ``raw_features_matrix.parquet``, and ``prep_metadata.json``.
    """
    from kreview.eval_engine import multimodal_prep as _multimodal_prep

    print("=== kreview eval multimodal prep ===", flush=True)
    print(f"  --results-dir        : {results_dir}", flush=True)
    print(f"  --super-matrix       : {super_matrix or '(not provided)'}", flush=True)
    print(f"  --multimodal-selection: {multimodal_selection}", flush=True)
    print(f"  --top-percentile     : {top_percentile}", flush=True)
    print(f"  --output             : {output}", flush=True)
    print("", flush=True)

    log.info(
        "eval_multimodal_prep_start",
        results_dir=str(results_dir),
        super_matrix=str(super_matrix) if super_matrix else None,
    )

    if not results_dir.exists():
        print(f"ERROR: Results directory not found: {results_dir}", flush=True)
        raise typer.Exit(code=1)

    t0 = _time.time()
    try:
        metadata = _multimodal_prep(
            results_dir=results_dir,
            super_matrix_path=super_matrix,
            multimodal_selection=multimodal_selection,
            top_percentile=top_percentile,
            random_state=seed,
            output_dir=output,
        )
    except (FileNotFoundError, ValueError) as e:
        print(f"ERROR: {e}", flush=True)
        log.error("multimodal_prep_failed", error=str(e))
        raise typer.Exit(code=1)
    except Exception as e:
        log.error("multimodal_prep_unexpected_error", error=str(e))
        print(f"ERROR: Unexpected error: {e}", flush=True)
        raise typer.Exit(code=1)

    elapsed = _time.time() - t0
    print(f"  Evaluators: {metadata['n_evaluators']}", flush=True)
    print(f"  Stacking matrix: {metadata['stacking_shape']}", flush=True)
    if metadata.get("has_raw_features"):
        print(f"  Raw features matrix: {metadata['raw_shape']}", flush=True)
    print(f"\n=== eval multimodal prep complete ({elapsed:.1f}s) ===", flush=True)


# ── eval multimodal single ────────────────────────────────────────────────────


@multimodal_app.command("single")
def eval_multimodal_single(
    stacking_matrix: Path = typer.Option(
        ...,
        "--stacking-matrix",
        help="Path to stacking_matrix.parquet from multimodal prep",
    ),
    model: str = typer.Option(
        "rf",
        "--model",
        help="Model to train: rf, xgb, lr, tabpfn_ft, tabicl_ft",
    ),
    raw_features_matrix: Path = typer.Option(
        None,
        "--raw-features-matrix",
        help="Optional path to raw_features_matrix.parquet from prep",
    ),
    cv_folds: int = typer.Option(5, "--cv-folds", help="Cross-validation folds"),
    device: str = typer.Option("cuda", "--device", help="PyTorch device"),
    finetune_epochs: int = typer.Option(
        50, "--finetune-epochs", help="GPU fine-tuning epochs"
    ),
    finetune_lr: float = typer.Option(
        1e-5, "--finetune-lr", help="GPU fine-tuning learning rate"
    ),
    best_single_auc: float = typer.Option(
        0.0,
        "--best-single-auc",
        help="Best single-evaluator AUC for delta computation",
    ),
    seed: int = typer.Option(42, "--seed", help="Random seed"),
    deterministic: bool = typer.Option(
        True,
        "--deterministic/--no-deterministic",
        help="Enable PyTorch deterministic mode.",
    ),
    output: Path = typer.Option("output/", help="Output directory"),
):
    """Stage 2: Train one model on the stacking (+ optional raw) matrix.

    Produces ``stacking_{model}_results.json``.
    """
    from kreview.eval_engine import multimodal_single as _multimodal_single
    from kreview.reproducibility import seed_everything

    seed_everything(seed, deterministic=deterministic)

    print("=== kreview eval multimodal single ===", flush=True)
    print(f"  --stacking-matrix    : {stacking_matrix}", flush=True)
    print(f"  --model              : {model}", flush=True)
    print(f"  --raw-features-matrix: {raw_features_matrix or '(none)'}", flush=True)
    print(f"  --cv-folds           : {cv_folds}", flush=True)
    print(f"  --device             : {device}", flush=True)
    print(f"  --finetune-epochs    : {finetune_epochs}", flush=True)
    print(f"  --output             : {output}", flush=True)
    print("", flush=True)

    log.info("eval_multimodal_single_start", model=model)

    if not stacking_matrix.exists():
        print(f"ERROR: Stacking matrix not found: {stacking_matrix}", flush=True)
        raise typer.Exit(code=1)

    t0 = _time.time()
    try:
        results = _multimodal_single(
            stacking_matrix_path=stacking_matrix,
            model_name=model,
            raw_features_path=raw_features_matrix,
            n_folds=cv_folds,
            random_state=seed,
            device=device,
            finetune_epochs=finetune_epochs,
            finetune_lr=finetune_lr,
            best_single_auc=best_single_auc,
            output_dir=output,
        )
    except (FileNotFoundError, ValueError) as e:
        print(f"ERROR: {e}", flush=True)
        log.error("multimodal_single_failed", model=model, error=str(e))
        raise typer.Exit(code=1)
    except Exception as e:
        log.error("multimodal_single_unexpected_error", model=model, error=str(e))
        print(f"ERROR: Unexpected error: {e}", flush=True)
        raise typer.Exit(code=1)

    elapsed = _time.time() - t0
    stacking_auc = results.get(f"auc_stacking_{model}", "N/A")
    print(f"  Stacking AUC ({model}): {stacking_auc}", flush=True)
    raw_auc = results.get(f"auc_raw_{model}")
    if raw_auc is not None:
        print(f"  Raw AUC ({model}): {raw_auc}", flush=True)
    print(f"\n=== eval multimodal single complete ({elapsed:.1f}s) ===", flush=True)


# ── eval multimodal ablation ──────────────────────────────────────────────────


@multimodal_app.command("ablation")
def eval_multimodal_ablation(
    stacking_matrix: Path = typer.Option(
        ...,
        "--stacking-matrix",
        help="Path to stacking_matrix.parquet from multimodal prep",
    ),
    stacking_results_dir: Path = typer.Option(
        ...,
        "--stacking-results-dir",
        help="Directory with stacking_*_results.json from multimodal single",
    ),
    cv_folds: int = typer.Option(5, "--cv-folds", help="Cross-validation folds"),
    seed: int = typer.Option(42, "--seed", help="Random seed"),
    output: Path = typer.Option("output/", help="Output directory"),
):
    """Stage 3: Leave-one-evaluator-out ablation analysis.

    Uses the best stacking model to measure each evaluator's marginal
    contribution.  Produces ``ablation_results.json``.
    """
    from kreview.eval_engine import multimodal_ablation as _multimodal_ablation

    print("=== kreview eval multimodal ablation ===", flush=True)
    print(f"  --stacking-matrix     : {stacking_matrix}", flush=True)
    print(f"  --stacking-results-dir: {stacking_results_dir}", flush=True)
    print(f"  --cv-folds            : {cv_folds}", flush=True)
    print(f"  --output              : {output}", flush=True)
    print("", flush=True)

    log.info("eval_multimodal_ablation_start")

    if not stacking_matrix.exists():
        print(f"ERROR: Stacking matrix not found: {stacking_matrix}", flush=True)
        raise typer.Exit(code=1)
    if not stacking_results_dir.exists():
        print(
            f"ERROR: Stacking results dir not found: {stacking_results_dir}",
            flush=True,
        )
        raise typer.Exit(code=1)

    t0 = _time.time()
    try:
        results = _multimodal_ablation(
            stacking_matrix_path=stacking_matrix,
            stacking_results_dir=stacking_results_dir,
            n_folds=cv_folds,
            random_state=seed,
            output_dir=output,
        )
    except (FileNotFoundError, ValueError) as e:
        print(f"ERROR: {e}", flush=True)
        log.error("multimodal_ablation_failed", error=str(e))
        raise typer.Exit(code=1)
    except Exception as e:
        log.error("multimodal_ablation_unexpected_error", error=str(e))
        print(f"ERROR: Unexpected error: {e}", flush=True)
        raise typer.Exit(code=1)

    elapsed = _time.time() - t0
    print(f"  Ablation model: {results.get('ablation_model')}", flush=True)
    ablation = results.get("ablation", {})
    for eval_name, info in list(ablation.items())[:5]:
        if "error" not in info:
            print(
                f"    {eval_name}: Δ={info.get('delta', 0):.3f}",
                flush=True,
            )
    print(f"\n=== eval multimodal ablation complete ({elapsed:.1f}s) ===", flush=True)


# ── eval multimodal merge ─────────────────────────────────────────────────────


@multimodal_app.command("merge")
def eval_multimodal_merge(
    stacking_results_dir: Path = typer.Option(
        ...,
        "--stacking-results-dir",
        help="Directory with stacking_*_results.json from multimodal single",
    ),
    prep_metadata: Path = typer.Option(
        ...,
        "--prep-metadata",
        help="Path to prep_metadata.json from multimodal prep",
    ),
    ablation_results: Path = typer.Option(
        None,
        "--ablation-results",
        help="Optional path to ablation_results.json from multimodal ablation",
    ),
    output: Path = typer.Option("output/", help="Output directory"),
):
    """Stage 4: Merge partial results into unified multimodal_results.json.

    Combines prep metadata, per-model stacking results, and optional
    ablation into a single output matching the monolithic schema.
    """
    from kreview.eval_engine import multimodal_merge as _multimodal_merge

    print("=== kreview eval multimodal merge ===", flush=True)
    print(f"  --stacking-results-dir: {stacking_results_dir}", flush=True)
    print(f"  --prep-metadata       : {prep_metadata}", flush=True)
    print(f"  --ablation-results    : {ablation_results or '(none)'}", flush=True)
    print(f"  --output              : {output}", flush=True)
    print("", flush=True)

    log.info("eval_multimodal_merge_start")

    if not prep_metadata.exists():
        print(f"ERROR: Prep metadata not found: {prep_metadata}", flush=True)
        raise typer.Exit(code=1)

    t0 = _time.time()
    try:
        results = _multimodal_merge(
            stacking_results_dir=stacking_results_dir,
            prep_metadata_path=prep_metadata,
            ablation_path=ablation_results,
            output_dir=output,
        )
    except (FileNotFoundError, ValueError) as e:
        print(f"ERROR: {e}", flush=True)
        log.error("multimodal_merge_failed", error=str(e))
        raise typer.Exit(code=1)
    except Exception as e:
        log.error("multimodal_merge_unexpected_error", error=str(e))
        print(f"ERROR: Unexpected error: {e}", flush=True)
        raise typer.Exit(code=1)

    elapsed = _time.time() - t0
    stacking = results.get("stacking", {})
    n_stacking_keys = sum(1 for k in stacking if k.startswith("auc_stacking_"))
    print(f"  Models merged: {n_stacking_keys}", flush=True)
    print(f"  Has ablation: {'ablation' in results}", flush=True)
    print(f"  Has raw features: {'raw_features' in results}", flush=True)
    print(f"\n=== eval multimodal merge complete ({elapsed:.1f}s) ===", flush=True)
